A debounce function delays the execution of a function until a certain amount of time has passed without further calls.

```javascript
function debounce(func, delay) {
  let timeoutId;
  return function(...args) {
    clearTimeout(timeoutId);
    timeoutId = setTimeout(() => {
      func.apply(this, args);
    }, delay);
  };
}

// Example Usage:

function search(query) {
  console.log(`Searching for: ${query}`);
}

const debouncedSearch = debounce(search, 500); // Wait 500ms before executing

// Simulate rapid key presses
debouncedSearch("apple");
debouncedSearch("appl");
debouncedSearch("app");
debouncedSearch("appl");
debouncedSearch("apple"); // Only this one will trigger the search after 500ms

// After 500ms from the last call, "Searching for: apple" will be logged.
```
